// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader !== undefined ? headers[apiKeyHeader] : '';
const expectedKey = $env.LOCALAI_API_KEY;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;
  // Normalize both to exactly MAX_LEN characters (truncate or pad with \0)
  const aPadded = a.slice(0, MAX_LEN).padEnd(MAX_LEN, '\0');
  const bPadded = b.slice(0, MAX_LEN).padEnd(MAX_LEN, '\0');

  let result = 0;
  // Constant-time comparison: always iterate MAX_LEN, no early returns
  for (let i = 0; i < MAX_LEN; i++) {
    result |= aPadded.charCodeAt(i) ^ bPadded.charCodeAt(i);
  }
  // Include original length check in constant-time result
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

// CRITICAL: Always validate API key if provided, regardless of expectedKey
// This prevents fail-open vulnerability when env var is unset
// Authentication logic:
// - If server has expectedKey configured: client MUST provide matching key
// - If server has NO expectedKey configured: reject any request that provides a key (unauthorized)
// - If neither configured: allow (no auth required)
if ((expectedKey || providedKey) && !timingSafeEqual(providedKey || '', expectedKey || '')) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

const input = $input.first().json || {};
const message = input.message || '';
const model = input.model || 'local-model';
const temperature = input.temperature;
const maxTokens = input.max_tokens;

// === MODEL VALIDATION ===
const validModelPattern = /^[a-zA-Z0-9._-]+$/;
if (!validModelPattern.test(model)) {
  return [{ json: { valid: false, error: 'Invalid model name: must be alphanumeric, dot, dash, or underscore only' } }];
}
if (model.length > 100) {
  return [{ json: { valid: false, error: 'Model name too long: max 100 characters' } }];
}

// === MESSAGE LENGTH VALIDATION ===
if (typeof message !== 'string') {
  return [{ json: { valid: false, error: 'Invalid message: must be a string' } }];
}
if (message.length > 32768) {
  return [{ json: { valid: false, error: 'Message too long: max 32768 characters' } }];
}
if (message.length === 0) {
  return [{ json: { valid: false, error: 'Missing required field: message' } }];
}

// === TEMPERATURE VALIDATION ===
const tempValue = temperature !== undefined ? parseFloat(temperature) : 0.7;
if (isNaN(tempValue) || tempValue < 0.0 || tempValue > 2.0) {
  return [{ json: { valid: false, error: 'Invalid temperature: must be a number between 0.0 and 2.0' } }];
}

// === MAX TOKENS VALIDATION ===
const tokensValue = maxTokens !== undefined ? parseInt(maxTokens, 10) : 1024;
if (isNaN(tokensValue) || tokensValue < 100 || tokensValue > 4096) {
  return [{ json: { valid: false, error: 'Invalid max_tokens: must be an integer between 100 and 4096' } }];
}

// === CHANNEL VALIDATION ===
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  return [{ json: { valid: false, error: 'Invalid channel: must be alphanumeric, dash, or underscore only' } }];
}

return [{
  json: {
    valid: true,
    message: message,
    model: model,
    temperature: tempValue,
    max_tokens: tokensValue,
    channel: channelRaw,
    stream: false
  }
}];

// Process LocalAI response
const body = $input.first().json || {};

const message = body.choices?.[0]?.message?.content || body.message?.content || 'No response generated';
const model = body.model || 'unknown';
const usage = body.usage || {};

return [{
  json: {
    valid: true,
    success: !!message,
    model: model,
    response: message,
    tokens_used: usage.total_tokens || 0,
    prompt_tokens: usage.prompt_tokens || 0,
    completion_tokens: usage.completion_tokens || 0,
    timestamp: new Date().toISOString()
  }
}];
